INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务很周到，门童会主动打招呼并帮忙拿行李，去客房电梯口也有工作人员指引，chec', '服务很周到，门童会主动打招呼并帮忙拿行李，去客房电梯口也有工作人员指引，checkin柜台小姐姐Viria很热情且耐心。酒店环境不错，后面有个小花园，唯一欠缺是房间设施有些旧了，卫生间通风换气不佳。', '2024-02-21', 4, '[''前台服务'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232z12000d9gf3sb94C5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230e12000d9gej8762E0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231a12000d9gebu48428_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '有史以来入住等待时间最久的一家酒店，大堂人员嘈杂，乱哄哄的，体验极差，前台服务人', '有史以来入住等待时间最久的一家酒店，大堂人员嘈杂，乱哄哄的，体验极差，前台服务人员一点不急，在那里慢吞吞的。客房装修老旧，堪比快捷酒店。水龙头设计不合理，一打开水溅的台面上一塌糊涂。淋浴和马桶共用一扇门，关上淋浴，用马桶的就没有门了，敞开着上厕所。奇葩省钱装修。淋浴间瓷砖破损，茶几磨损严重，还在坚持给客人使用。完全与五星不搭。这个酒店真是金玉其外……。', '2024-02-12', 2, '[''前台服务'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230s12000d6pfgw9F0B8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232g12000d6pgw4fD345_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境不错 行李生服务特别好  客房大姐也很热情', '环境不错 行李生服务特别好  客房大姐也很热情', '2024-06-16', 5, '[''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232s12000ehpvuldD3D4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l12000ehpyrl92A6E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230g12000ehpxi63DDC0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店除了地理位置优越，服务几十年来没有任何降低，酒店的房间干净大气，充分体现', '花园酒店除了地理位置优越，服务几十年来没有任何降低，酒店的房间干净大气，充分体现国际酒店的水平。酒店的各类服务人员，态度和素质非常高，超越很多新的酒店。广州酒店，首选花园酒店是绝对不会错的', '2024-02-17', 5, '[''整体满意度'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0232a12000d8adntt392A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '入住环境真的是很好，酒店自带一个那么大花园很惊叹了。而且春节期间，过年气氛搞得特', '入住环境真的是很好，酒店自带一个那么大花园很惊叹了。而且春节期间，过年气氛搞得特别浓，特别喜庆热闹，感觉随时有节目随时有惊喜，孩子遇到好几次财神高兴的不得了，几块金币巧克力带来的欢乐??愉快了整个旅程。服务也很好，热情又主动，前台接待、大堂经理、餐厅工作人员都很积极。整体入住体验很满意。', '2024-02-20', 5, '[''整体满意度'', ''前台服务'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235w12000d98wbus72E3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234d12000d98w5ozAA02_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231112000d98vz9m4163_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232d12000d98wbv0E917_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第2次入住花园，地理位置好，离北京路很近，办理入住可以再便捷快一点，房间干净，床', '第2次入住花园，地理位置好，离北京路很近，办理入住可以再便捷快一点，房间干净，床垫偏软，早餐在一楼，地方不大，有安排座位，餐品一般，种类不多，参观了花园博物馆，里面陈列的是以花园酒店为主的广州酒店发展史。总体感觉一般。', '2024-02-15', 4, '[''周边配套'', ''退房/入住效率'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0233012000d7ma3gqA78B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235v12000d7ma54l8432_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间总体保养不错，就是淋浴下水有些不畅，可能是时代有些久远。酒店内瀑布花园，顶层', '房间总体保养不错，就是淋浴下水有些不畅，可能是时代有些久远。酒店内瀑布花园，顶层 360旋宫餐厅是酒店亮点，住酒店有空值得一去。旋宫可以俯视全城美景，瀑布花园小而精致，很有岭南风味，点赞！', '2024-02-15', 5, '[''房间设施'', ''公共设施'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0230h12000d7o92ef14C0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235h12000d7o9dyw1A84_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234e12000d7o0qglD729_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236m12000d7nzoe80DD7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '每次来广州都喜欢住花园酒店，酒店服务始终保持着传统的管家式的贴心，行李房，楼层管', '每次来广州都喜欢住花园酒店，酒店服务始终保持着传统的管家式的贴心，行李房，楼层管理，房间整理，都一如既往地规范有礼，路上员工也会主动跟客人打招呼，而且酒店大堂的布置总是那么富有岭南特色。', '2024-02-21', 5, '[''前台服务'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232e12000d9bhs19EBCF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232d12000d9bhe0cB10A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店环境很好，瀑布餐厅很美，服务很好，办理入住送了鲜花，房间整体不错，有迎宾水果', '酒店环境很好，瀑布餐厅很美，服务很好，办理入住送了鲜花，房间整体不错，有迎宾水果，过生日还送了蛋糕，服务员Amy写的小卡片很贴心，很不错的入住体验，下次来广州还会考虑住花园酒店！', '2024-12-10', 5, '[''整体满意度'', ''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234i12000h4pbgag2A1A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233f12000h4p4yb18FD3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '作为老广，花园酒店一直都是属于高档酒店的存在，没想到入住大失所望，房间设施陈旧就', '作为老广，花园酒店一直都是属于高档酒店的存在，没想到入住大失所望，房间设施陈旧就不说了，浴室卫生简直以灾难级形容，大理石裂的，洗脸盆和淋浴间的霉菌简直吓人，很难想象跟星级扯上关系', '2024-02-15', 2, '[''房间设施'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0236x224x8u1bbeva867C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230l224x8u1cd07b2F68_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02359224x8u1cdw3j362D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02337224x8u1bnuz2593F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231q224x8u1bbevcE5F0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234d224x8u1b2ynyDBCD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02303224x8u1cd07dB629_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234m224x8u1cfbfgFDDB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236z224x8u1bz417FE33_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '选择住花园酒店时还有点纠结，虽然也是五星，但年代久远，硬件设施确实还有改进的空间', '选择住花园酒店时还有点纠结，虽然也是五星，但年代久远，硬件设施确实还有改进的空间，但也因为是老牌五星，对于我们这种没体验过的外地游客而言，还是很新奇，瀑布、花园、博物馆这些无论对于大人还是孩子而言，都还是不错的体验。应该说特色突出，值得一试。但是入住和退房都要排队，有点尴尬，携程的铂金会员也要押金，好在办了个岭南酒店金卡，送了小朋友早餐还是不错的，而且瀑布餐厅和楼上的旋转餐厅，孩子都很喜欢，总体来说还是很满意的！对了，在地铁口也非常重要，超级方便！', '2024-03-20', 4, '[''整体满意度'', ''交通便利性'', ''退房/入住效率'']', '["[ \"https://dimg04.c-ctrip.com/images/0236x12000dgi8s56305C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230l12000dgi8svqC8C7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232812000dgi8ue63237_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230512000dgi95cfDEF4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '家庭出游定了双床房，整个交通，酒店环境都还不错。但只有三分的原因就是这个洗手间和', '家庭出游定了双床房，整个交通，酒店环境都还不错。但只有三分的原因就是这个洗手间和浴缸（没有淋浴间）是正对房间两个床，也就是家里有异性的话，无可避免的要有几分钟暴露时间，因为你不能在浴缸里穿衣服，而且也没地方放干净的衣服，如果家里有老人，跨进跨出洗澡还非常有难度！这个设计是我不能理解的。就算是好朋友一起出游，我想也不太好意思洗完澡出来就被看光吧？？？
另外，我在六楼，需要补给我去找走廊打扫的小妹，外籍小姑娘说“听不懂”，只能用英语交流，我想说，你在中国的土地上打工，你听不懂？？？这个需要客房部培训一下了。我可以讲英语，但是你不能不会中文哦！', '2024-02-11', 3, '[''房间设施'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233112000d6d6stbD701_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231z12000d6de616286D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231n12000d6d53jg7C8D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '孩子们非常喜欢花园酒店，装修精致，服务贴心，后花园景色优美，欣赏瀑布尝心悦目，酒', '孩子们非常喜欢花园酒店，装修精致，服务贴心，后花园景色优美，欣赏瀑布尝心悦目，酒店的文创商品也非常有特色，荔湾亭的食物让人流连忘返，酒店交通便捷，距离地铁站很近，酒店各方面都让人很满意，下次还会入住。', '2024-02-17', 5, '[''整体满意度'', ''周边配套'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0233p12000d8a1ojt7045_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230312000d8a0p6yAF5E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232912000d89um1d1DAF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235912000d89y9n73564_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236f12000d8a2lm9A923_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店非常气派，大开眼界！ 长辈都夸好。', '酒店非常气派，大开眼界！ 长辈都夸好。
定的64平的套房，宽敞舒适，客房服务响应及时，行李搬运也到位。
第一天图省事去了荔湾艇吃饭，有点不愉快，性价比不高。
下次还会选择入住花园酒店，吃饭还是去外面吃更好。', '2024-02-07', 5, '[''整体满意度'', ''客房服务'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0230l12000d5gnaw1A048_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234z12000d5gm5e4060E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235412000d5gmove385E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231412000d5gnb1s8B55_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232w12000d5gnb1w1AA9_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次旅行挑酒店??最快，选了花园酒店。看评价差评多有点忐忑但是一下车真的很棒，门', '这次旅行挑酒店??最快，选了花园酒店。看评价差评多有点忐忑但是一下车真的很棒，门童主动拿行李??，每个服务人员态度好，办理入住也特别快，房间干净整洁，有咖啡机胶囊咖啡免费，和新加坡????茶。连住三晚每天及时打扫??。酒店的桃园亭吃的早茶，人特别少，味道不错就是贵和白天鹅??差不多优点就是不用排队，就两三桌。酒店门口很近就有点都德，对面的街有好多好吃的嫌北京路远可以去酒店对面溜溜，还有个优点就是离地铁站非常近这个是我选择这个酒店的重要原因！唯一缺点就是不能开窗，身为北方人总觉得有点潮味儿。总之很满意放心入住', '2024-02-16', 4, '[''前台服务'', ''交通便利性'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0231x12000d7sezd24052_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236m12000d7setzhB78E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236p12000d7sf6gj87CC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232t12000d7sezd47D41_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '每家五星级酒店都有自己的风格！广州花园酒店拥有自己的博物馆，自己的花园，自己的米', '每家五星级酒店都有自己的风格！广州花园酒店拥有自己的博物馆，自己的花园，自己的米其林餐厅！可以媲美上海的和平饭店??！客房服务真的非常人性化！感觉宾至如归！来广州过年，花园酒店的布景，年味浓郁！感觉特别好！', '2024-02-09', 5, '[''整体满意度'', ''客房服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0203j12000d61vpn67489_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0235y12000d61irig6C8E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231h12000d61mn7t5856_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236812000d61v8nh12A6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235z12000d61j3m4223B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234g12000d61ijgx30B6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232m12000d61npig8680_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '慕名而来，酒店服务各方面还可以。因为我们山西大同也有个花园酒店非常棒的，听说他们', '慕名而来，酒店服务各方面还可以。因为我们山西大同也有个花园酒店非常棒的，听说他们都美食就是在这里学习的说以想感受一下，也许不适合我们北方人都口味，感觉还是我们大同美食才是天下第一，欢迎大家来大同感受一下，', '2024-02-22', 5, '[''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0205z12000d9r4bl53476_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0231o12000d9qxlwl5B44_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231o12000d9r39oe02C9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234g12000d9qp18dD65F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店正门右边就是地铁5号线淘金站，交通便利，不想坐地铁，服务员会在外面帮你叫出租', '酒店正门右边就是地铁5号线淘金站，交通便利，不想坐地铁，服务员会在外面帮你叫出租车，服务非常好！
酒店大堂装潢非常漂亮，接待入住的前台美女服务也特别热情！早餐种类也非常丰富，你可以选择在一楼的瀑布餐厅，也可以选择在30楼旋转餐厅用餐！个人偏向推荐一楼瀑布餐厅，但是要记得早点去，八点半九点时去的话有可能需要排队等位哟！
房间也非常干净，每天都会打扫，如果你在房间开了请勿打扰，服务员也会打电话询问是否打扫房间，什么时间打扫房间合适，所以服务特别贴心！
大年初一那天酒店还请来了专业的舞狮团队来表演，特别哇塞！', '2024-02-15', 5, '[''交通便利性'', ''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0206712000d7o39bbA1A6_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0235q12000d7o1r2qAFFB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230y12000d7nsvv6D78C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230d12000d7nwbof4153_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '都很满意，出地库就有漂亮小姐姐帮忙拿行李引路。还有欢迎糖果，和离店小礼物。酒店后', '都很满意，出地库就有漂亮小姐姐帮忙拿行李引路。还有欢迎糖果，和离店小礼物。酒店后花园是隐藏在闹市里的世外桃源，美美的！很出片！下次去还住花园酒店！周边很方便，饭后遛食，一杯小酒惬意的很！', '2024-02-14', 5, '[''整体满意度'', ''前台服务'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0234m12000d7b2ym55209_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236112000d7b2eqh5649_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230b12000d7b2whd5DD9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236312000d7b2xik9C05_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231k12000d7b3b3z80C3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234m12000d7b3mm699AE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231u12000d7b3hs2F3D8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233812000d7b2iiiE39C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店真的是目前住过最有底蕴的酒店，一进入大厅就能感受到。前台办理入住非常快，', '花园酒店真的是目前住过最有底蕴的酒店，一进入大厅就能感受到。前台办理入住非常快，虽然排队的人多但是窗口非常多很快就到了。前台Gillian非常专业迅速，得知我们是金卡会员并且过生日迅速安排房型升级超级认真负责，还送了鲜花超好评。行政酒廊待遇也非常全面，包含了早餐，下午茶和晚上的欢乐时光。
早餐种类非常多，在30楼旋转餐厅，每次都会带领我们入座。在我们记错时间错过下午茶时间后，Carrie女士立刻为我们安排第二天补上。即使不在服务时间，另外几位女士也为我们制作了两杯咖啡。二天我们入座后Carrie立刻前来询问我们的需求。
此外，我们住宿的16层电梯口也也服务的女生，我们安排电梯。
花园酒店的服务团队非常非常专业，非常庆幸这次能够选择花园酒店。', '2024-07-21', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232x12000euns61q4F60_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236o12000eunvsyw002A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234212000eunsaaoFADC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233o12000eunr5cgC79B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232g12000eunlun62212_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常巨大的酒店，所以入住要排队很久……大厅很国际化，设施还不错。第一次安排的房间', '非常巨大的酒店，所以入住要排队很久……大厅很国际化，设施还不错。第一次安排的房间一进门就是浓浓的蒜蓉生蚝味道，虽说闻起来不错，可实在不适合入住吧。之前就听闻早餐是米其林级别的，所以都订购了含早的房型，第一天体验还可以，虽说选择不多，餐厅比较小，有点局促，但餐厅后的瀑布还比较特别。第二天的早餐因为人太多，被忽悠到了旁边的酒吧，进去前一直被告知菜品是一样的，结果酒吧里不仅很冷，还没什么吃的，本来没什么胃口，只想喝完热粥，哪知道连这么卑微的要求都不能满足。敞开的粥锅里只剩一个底儿，还得排队抢，好不容易盛好了粥，还居然是冰粥。酒吧的服务人员一直在保障外国友人，国人在她们眼中，大概就是被施舍的吧，体验非常非常差，这样的品质也好意思说自己米其林？也好意思收200+的价格？现在是2024年了，拜托酒店醒醒吧，不是只有服务好外国友人就可以万事大吉的时候了。很糟糕的体验。再也不会来这样一家徒有虚名的虚伪酒店了。', '2024-02-20', 2, '[''餐饮设施'', ''整体满意度'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0235812000d914evn8F54_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '著名的花园酒店，非常喜欢那种文化气息和岁月的底蕴，同时自然也会有设施维护的问题，', '著名的花园酒店，非常喜欢那种文化气息和岁月的底蕴，同时自然也会有设施维护的问题，比如用水时下水管道会发出响声，沙发上会有污渍，但服务也非常周到，除了入住时前台不清楚套餐包含的桃园馆餐次数，说要核实后告知，不过一直没有回音，后来主动问过一次，也没有回话，除此而外，服务特别好，比如无论去餐厅还是乘电梯都有人引导，退房体验特别好特别方便以及人性化。下午茶和欢乐时光体验也很美好。总之，满意，再去广州会再选花园。', '2024-02-06', 4, '[''整体满意度'', ''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235f12000d59v0c7125D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230512000d5aijkzEAF2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231a12000d5aiin2059E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '购买了携程3晚连住花园双床房含早3600套餐，提前一周预约了房间。出发前一天跟客', '购买了携程3晚连住花园双床房含早3600套餐，提前一周预约了房间。出发前一天跟客房部打电话确认房型，要求高楼层安静无烟，对方回答会给备注。当天20点到达办理入住，说是帮我帮忙升级了9楼的城央绿意房，上去查看900是位于电梯间后面，浴缸和淋浴同处一处，考虑带孩子使用不便，便座机酒店客房部要求原房型入住。结果被告知已无类似房型。那么问题来了，我之前的全款预约、电话确认是为了什么？！座机沟通后被告知还有一间花园双床房在打扫，但无浴缸。我提出可否参观一下，被拒绝，并且打扫需要1.5小时左右，就是22点半以后！！毫无选择的我只能致电携程客服帮忙解决～就这么等了50分钟酒店和携程都没有任何回复。第三次致电携程后仍没有确切回复，自行前往大堂前台直接理论。诉求和理由同上。在前台交涉了50分钟，最终给了间23楼的红棉大床房加床处理，入住时接近22:30。我们不是无理取闹的人，只是争取合理的权益。好在后续酒店和携程在催促下有积极处理，结果还是满意的。说说酒店本身，地处老城区，餐饮交通真的方便。顶楼旋转餐厅风景好，餐食和服务都不错。所在楼层会有电梯间引导服务员，每次见面问好并确认房间号，挺安全的。图1-3是9楼的城央绿意房，除了浴缸淋浴不合理，其余中规中矩。图4是新装修的红棉房，推荐入住。携程平台还是很注意客户感受的，继续支持！', '2024-02-08', 4, '[''前台服务'', ''退房/入住效率'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234x12000d5um70s1B80_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000d5u8fjzE728_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236112000d5ujepx30C1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234c12000d5uchav48C0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间干净，环境很好', '房间干净，环境很好', '2024-07-13', 5, '[''卫生状况'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233112000eroqusg1AE9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235c12000erojtjw6044_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233112000eroquky5D33_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不知道为什么会有许多差评，对于一个比较挑剔的住客来讲首先我认为不错的。选了家庭大', '不知道为什么会有许多差评，对于一个比较挑剔的住客来讲首先我认为不错的。选了家庭大床房，服务很好，酒店下车时工作人员主动帮忙搬行李，每层都有导引人员，其次房间虽然不是非常大，但是干净温馨而舒适。巴基斯坦的小伙子很热情。作为白金五星酒店四楼的博物馆一定要去看看，那是时代的缩影，还有后花园，繁华喧嚣中的宁静与美好。唯一的遗憾是瀑布餐厅的早餐因为周六客满被换到了旋转餐厅，希望这一项能够改善，至少要保证住店客人用餐。', '2024-02-03', 5, '[''整体满意度'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230u12000d49hbp170F7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233w12000d49tivrDCE2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236g12000d49w5zd725C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '晚上7点多到的，前台给我们升级了套房，房间大一倍，非常满意。', '晚上7点多到的，前台给我们升级了套房，房间大一倍，非常满意。
房间舒适干净，又大，非常满意
酒店就是个花园，瀑布，亭台楼阁，又有深厚的文化底蕴，4楼有个酒店博物馆，好逛，非常满意
工作人员服务态度很好，看到住客主动打招呼，还有不同的活动领了冰箱贴，非常满意！
下次还会再来住！', '2024-02-09', 5, '[''整体满意度'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234i12000d5yk4u61E41_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000d5yjk4wEBB4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p12000d5yk7of383A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第一次入住，很成熟高雅的酒店。花园酒店的Rebecca还给升级了房间，必须点个赞', '第一次入住，很成熟高雅的酒店。花园酒店的Rebecca还给升级了房间，必须点个赞！', '2024-05-21', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233112000e3h02acC28E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000e3gycdi0688_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231512000e3gzph884F1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '满意，舒服！安娜和李文服务热情周到，保洁员对客户提出要求及时记录（服务满意）餐厅', '满意，舒服！安娜和李文服务热情周到，保洁员对客户提出要求及时记录（服务满意）餐厅早餐美味，旁边有瀑布环境舒适', '2025-04-01', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230l12000jh0mcb0F34C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234812000jh05eu2E3FD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235312000jgzufl75FF4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间的设施有点老旧了，酒店大堂和后花园还可以。这酒店住的老外挺多的，重点来了。因', '房间的设施有点老旧了，酒店大堂和后花园还可以。这酒店住的老外挺多的，重点来了。因为老外多，我发现大厅餐厅的服务员就比较**，我们去吃早饭的时候遇到同样一起排队的老外就分在能看见瀑布的位置视野开阔，光线明亮，我们一家三口分的位置就是最最角落的不要说看看瀑布了连光线都很暗的，家人们谁懂啊，花600多就是去打卡瀑布的好吗。我看见我们前面的三个老外就坐的位置很好，我当时就emo了，问服务员有没有位置好点的嘛？大厅不是有很多空位置吗？我想坐到那边去，她说啊那是有人坐的，他们都在取餐，一边说的时候一边微笑，我听了就不开心了，吃饭的心情也没有，过一会不知怎么的大概看我不开心就给我们换位置到大厅了，重点来了，我去取咖啡的时候杯子着急拿走服务员就跟我说no finished 谁懂啊，我一中国人在广州玩又没有出国说啥英语啊，真的醉了，咱不是说排斥英语啊，就你环顾四周的时候就发现坐大厅好位置的都是老外，我严重怀疑这酒店服务员是**。最后酒店早餐真的很一般就同是五星级酒店的早餐来比不能说最差的，实在是一般。不建议去吃。', '2024-02-03', 3, '[''餐饮设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236112000d43ak44002F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231n12000d439zl62586_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235s12000d43arke538E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '超级漂亮的酒店，地理位置非常好，整个酒店进门就是香香的，给我们升级了套房，三大一', '超级漂亮的酒店，地理位置非常好，整个酒店进门就是香香的，给我们升级了套房，三大一小住起来很宽敞，很舒服的一次旅行，客房还送了小书包跟水果给宝宝，特别用心呢', '2024-03-06', 5, '[''整体满意度'', ''客房服务'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0232j12000dctkqbr9A37_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231m12000dct83q77958_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230d12000dcth2f6EC16_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231612000dctjphy62BD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236212000dctl6baA3A2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231y12000dct7vjhBFC7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232v12000dctoc29A7E8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店位置很好，环境优美，服务到位，床品舒服，早餐纯西式，周边有广东酒家、点都德早', '酒店位置很好，环境优美，服务到位，床品舒服，早餐纯西式，周边有广东酒家、点都德早茶非常不错！卫生需要注意，咖啡机和水壶感觉都不太干净！过年气氛很浓，大堂有自己的集市和乐队，热热闹闹，开开心心！', '2024-02-08', 4, '[''周边配套'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0234712000d5rdzk6E556_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232w12000d5remy15829_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235r12000d5rf5k569E9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236p12000d5rfevsB913_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233z12000d5rdddt189B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230g12000d5rf5k995A5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这是我住过最差的酒店（更别说是五星级酒店了），比招待所都不如，还五星。房间和卫生', '这是我住过最差的酒店（更别说是五星级酒店了），比招待所都不如，还五星。房间和卫生间冲凉房直通，冲凉换衣服都不方便，而且设施非常残旧，真的是招待所的硬件。
    冲凉房居然就是一个浴缸，排水又慢，冲个凉简直就是水漫金山，水泡到脚腕，无法排水，而且在浴缸跨来跨去影响人身安全，出来就是房间，无任何遮挡，招待所都不是如此吧？岂有此理！！
    卫生间又窄又残旧，进去又不方便，就是个招待所不如的地方。
    房间又小可能 10 平方左右，而且床又残旧，地板更残旧，反正没一样东西是好的。就是乡下的招待所都比花园酒店客房好。反正谁住谁遭殃。看看图片就知道。差评！差评！差评！重要事情说三遍！！', '2024-01-30', 1, '[''房间设施'', ''卫生状况'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236i12000d3119ic90B7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236s12000d30qrm5AF24_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232l12000d30qebnF6A5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235e12000d316hju06F2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236l12000d30v4171095_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '预订酒店时备注了这次入住是为了过生日如果情况允许希望能安排上好一点的房间。晚上九', '预订酒店时备注了这次入住是为了过生日如果情况允许希望能安排上好一点的房间。晚上九点到店办入住时迎来了小小客流高峰，需要排队等候。办理入住手续的时候，前台小姐姐Betty 安排了一个超完美的房间，她还特意提醒我房号是精心设置了一个“好意头”的房间，还热情的给我送了几支花花。真的是太有趣了！房间安排了升级，打开房门发现房间有主题精心布置过，还有新鲜的欢迎水果，非常感谢客房姐姐的安排！房间里处处都是细节，房间桌子上摆放着酒店不同餐厅不同特色打卡点的酒店指南，图文并茂有趣又生动。连墙上挂着的装饰画都有印着二维码，好奇地拿手机一扫，显示出来的就是客房里房间装饰上蕴含的各种岭南文化元素。让我异常惊喜的是，短短的文章中透露出不同的岭南特色文化，有种让住客在入住期间都能感受到这个酒店的文化底蕴和用意。唯一一个小小的插曲大概是我们不知道今天酒店会有赠送蛋糕到房间的这个惊喜。所以早上送的时候，估计服务员看到我们挂了请勿打扰灯，让前台打了电话来确认，刚好那个时间我们还在休息，电话来的时候会有一点感觉被吵醒到了。但总体来说这次入住非常不错的呢', '2024-09-11', 5, '[''前台服务'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231v12000fhuiq43E951_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230b12000fhu3svwD0DE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234h12000fhtpgqj4BDF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231212000fhufwt8C3A0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236p12000fhu9t8i841F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '风景很好，酒店有文化历史风韵。下次还会入住这里，续住了一日，非常满意。酒店周边很', '风景很好，酒店有文化历史风韵。下次还会入住这里，续住了一日，非常满意。酒店周边很多老酒家，适合美食爱好者。', '2024-04-25', 5, '[''整体满意度'', ''周边配套'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0235k12000ds5ynjv34C1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230512000ds60lf740B3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232n12000ds5s3wh96AB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230712000ds5ni6j9D2F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：大堂非常的富丽堂皇，现在是圣诞节的布置了，好浪漫。?瀑布餐厅也不错，房间的', '设施：大堂非常的富丽堂皇，现在是圣诞节的布置了，好浪漫。?瀑布餐厅也不错，房间的层高略矮，?以如今已是38年了，设施有点老旧，但是还是蛮干净的，床上用品很舒服，如果放在38年前绝对是顶级奢华。??
过来过生日的，酒店帮忙升级的房间，还帮忙做了布置，前台还送的了鲜花，谢谢每一位热心且用心的工作人员。
酒店的花园也是精心设计过的，但是略小，现在只有异木棉在开放。
酒店博物馆还不错，听说有免费的讲解，但是没赶上。
上上下下里里外外的每一个工作人员态度都非常好，大堂里穿粉红色裙子的小姐姐会热心的帮忙拍，而且拍照技术很赞，感谢感谢！
早餐比较一般，种类比较，但是环境很好。
送的点心很好吃！谢谢！
因为胃不好，不然高低吃顿午饭再走。
整体感觉不错，都在五星的水准，里里外外逛了个遍，没事就在房间里面写写字，很安逸。

?', '2023-12-11', 5, '[''整体满意度'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235r12000cprsuos5E53_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231k12000cps3hjy3280_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231k12000cps169e203B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236z12000cprw22p8475_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235q12000cprvbztF677_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234412000cps3r2cB5F3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231812000cps3rgdF2C9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230912000cprxjenB7D7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233y12000cps2sb0D762_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '1255556666699888888555555666658555555555', '12555566666998888885555556666585555555555555555638885 九点不错！！', '2024-06-19', 5, '[]', '["[ \"https://dimg04.c-ctrip.com/images/0235b12000eiqwg6m7688_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233c12000eiqzilh8041_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000eiqt5zoE21E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '作为全国3家白金五星级酒店，大堂富丽堂皇，后花园小桥流水，瀑布潺潺。4楼酒店博物', '作为全国3家白金五星级酒店，大堂富丽堂皇，后花园小桥流水，瀑布潺潺。4楼酒店博物馆不错，感受改革开放的岁月变迁，体会广州酒店业的发展历史和蓬勃生机。酒店门口地铁淘金站，去哪都很方便。稍显遗憾的是早餐种类不多，而且人多，排队时间长，体验不是很好。', '2024-02-11', 5, '[''交通便利性'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232d12000d6f3jvj4011_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230i12000d6f55izAE56_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235n12000d6eliyz4EBA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '本次购买的是套餐，包含自助晚餐和早餐，然后升级了一间房间为酒店景观房，十分美好，', '本次购买的是套餐，包含自助晚餐和早餐，然后升级了一间房间为酒店景观房，十分美好，花园酒店虽然老牌但质量和服务依然上乘，房间设计精巧古典。食物也很好，很多人来吃自助，早餐最好也要早点去。附近可以去对面马路的友谊商店逛逛，是广州最早的进出口商店。也可以坐地铁或公交去天河体育西一带购物游玩，地点而言十分方便。', '2024-02-21', 5, '[''餐饮设施'', ''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230412000d9g31ae58CF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很奇葩，开放式卫生间，马桶间和淋浴室共用一扇非常难拉的拉门，可以想象****', '房间很奇葩，开放式卫生间，马桶间和淋浴室共用一扇非常难拉的拉门，可以想象*******便秘的场景，而且住到第三天被褥就会开始返潮……沟通了下前台，这种奇葩装修是老板喜欢，果然品味清奇。早餐八点左右必然排队，餐品挺难吃，我一便宜嘴巴说难吃就真真的千真万确了??，我觉得这种难吃是不以人的意志而转移的??。行政酒廊没烈酒和调酒，比较少见，全冷餐，在空调不行的情况下对老人和妇幼有点不和谐，基本上脱不了外套。酒店所有服务人员的素质很高，非常热情，仅次于海景花园了。行政酒廊的早餐点餐是冷的??', '2024-01-29', 3, '[''房间设施'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234912000d2qxkre5497_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230z12000d2qvavt2D2A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233712000d2qo6602484_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232p12000d2r6sw2D1E7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店一直都是很稳定，先装修的房间很好，体现岭南设计风格。', '花园酒店一直都是很稳定，先装修的房间很好，体现岭南设计风格。', '2024-05-20', 5, '[''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/02328224x8uwpfvld3CB7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌五星，广州人妇孺皆知的豪华酒店，硬件不会让人失望。服务在广州五星酒店里算比较', '老牌五星，广州人妇孺皆知的豪华酒店，硬件不会让人失望。服务在广州五星酒店里算比较好的，不过因为刚在上海和平饭店住过，感觉还有进一步提升空间，例如服务的主动，还有真诚。如果有机会，酒店的有关人不妨自己掏腰包，以普通客人的身份，去上海和平饭店住一晚，吃一次饭，参观一次酒店的博物馆，体验一下差距。作为一个老广州，真心希望花园酒店这个金子招牌擦得更亮。', '2024-01-30', 5, '[''整体满意度'', ''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235t12000d2trhnt8953_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店的大堂很有特色，很多元素，中西合璧，金光闪闪，迎面的冲击感很强。', '花园酒店的大堂很有特色，很多元素，中西合璧，金光闪闪，迎面的冲击感很强。
岭南花园是酒店的特色，有四层楼高的瀑布，南国绿植，小桥流水加悠游的锦鲤，是一派太平盛世的景象。
最喜欢的部份是四楼博物馆，小姐姐洪亮的嗓音，标准的普通话讲解，把酒店发展的历史，广州酒店的历史以及花园酒店的特色娓娓道来。', '2024-01-31', 5, '[''公共设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230n12000d3cl8xeCEDF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232z12000d3cl57rF1C9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233v12000d3cl57t7958_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236g12000d3cl9p21263_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232u12000d3cl4ex2B90_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '基本满意，但是2024/1/27日在瀑布餐厅早餐的时候被一名服务人员（餐厅做鸡蛋', '基本满意，但是2024/1/27日在瀑布餐厅早餐的时候被一名服务人员（餐厅做鸡蛋卷的那个厨师，具体名称不清楚，就是鸡蛋摊开放菜丁的那个蛋饼）搞的心情不好，他摊好一个之后放在了台子上，我没有意识到是别人预定的，我就打算拿，刚拿起来，他就大声说“Order，understand？” ，我就放了回去，我就不明白了，你面对国内的客人，有必要说英文吗？而且还是呵斥的口吻，我很震惊，五星级老牌酒店，这种服务态度，而且还带有崇洋的潜意识，什么年代了，无语，本想投诉给餐厅经理的，行程太紧，没时间，这里吐槽一下，酒店的服务，硬件和软服务缺一不可，而且温馨的软服务才是取胜之道，总之这个人的服务影响了我对花园酒店的印象！', '2024-01-28', 3, '[''餐饮设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232k12000d2cu55f4519_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌白金五星底蕴还是非常深厚的 酒店本身就自带景点 餐饮配套等均在水准！', '老牌白金五星底蕴还是非常深厚的 酒店本身就自带景点 餐饮配套等均在水准！
入住期间室外游泳池维修中没有体验 如有室内泳池更佳。
老酒店隔音是减分项，此次房间安排在布草间对面，保洁阿姨的开关门声聊天声都能听到，如对隔音有要求需慎选。', '2024-01-29', 3, '[''公共设施'', ''安静程度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232i12000d2loon5257A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232n12000d2lqkdx21B3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234u12000d2lretx6FA2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一家有情怀有历史的老牌酒店是值得入住的，特别是四楼的博物馆绝对加分，让顾客了解酒', '一家有情怀有历史的老牌酒店是值得入住的，特别是四楼的博物馆绝对加分，让顾客了解酒店的昨天和今天；后花园的颜值也是值得欣赏的。但是由于房间安排在电梯旁晚上总有上上下下电梯的声音，体验度不是很好；加上晚上九点多楼上还在类似发出维修的电钻和敲打声，这个暴露了管理的不精细的有违酒店顾客的酒店文化。', '2024-01-27', 4, '[''安静程度'', ''整体满意度'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233112000d25pedm5F86_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233i12000d25pmxb0BED_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232h12000d25zenk5FE8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店大堂富丽堂皇，第一眼看到有被震惊到，涨见识了！酒店处处是艺术风景，后花园也很', '酒店大堂富丽堂皇，第一眼看到有被震惊到，涨见识了！酒店处处是艺术风景，后花园也很美，值得来。这是一家有历史，文化底蕴的酒店，所以以前的房间设施相对旧点，但总体感受很好！', '2024-02-20', 4, '[''整体满意度'', ''公共设施'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232e12000d91lfstDB4C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233d12000d91ogui461E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q12000d91yjggFB1B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '??套餐里的行政早餐实在拉垮 自助部分屈指可数 点单部分第一天还行还有摆盘 第二', '??套餐里的行政早餐实在拉垮 自助部分屈指可数 点单部分第一天还行还有摆盘 第二天直接像换了厨师我的煎蛋们缩水了 吃了两天还是乖乖回一楼瀑布餐厅吃了 很热门 周末早餐到11点 11:30午市开始
??来之前得多刷刷评论啊 原来楼下在修地铁好像 避雷各楼层19-34号这一排房间（应该是）总之入住前一定要问清楚修路是哪一边的房间 第一晚凌晨两点还在开挖掘机真是服了 
??入住晚了 被告知楼层是吸烟楼层 会放一台空气净化器 
??后面的花园是真漂亮
??服务可以 礼宾部的几位不错
??出行方便 门口就是地铁', '2024-01-31', 4, '[''餐饮设施'', ''安静程度'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0234t12000d33hbc29989_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233v12000d33g5stCCD8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234112000d332dha3257_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236s12000d3383ng121B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234c12000d33gxp84AB7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230a12000d3332tb57CA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店紧邻地铁站，出行非常方便。酒店大堂非常壮观，一进去就忍不住要拍照，服务人员热', '酒店紧邻地铁站，出行非常方便。酒店大堂非常壮观，一进去就忍不住要拍照，服务人员热情周到，但进入房间还是有点失望的，毕竟年头长了，设施老旧现状无法避免，洗浴池地漏堵水，洗个澡要洗洗停停，非常不便，期待改进！', '2024-01-27', 4, '[''房间设施'', ''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231y12000d24a48x782D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232f12000d24hlh4A9D9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234q12000d24jqvfDFC0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店很大气，一入户，大厅里金碧辉煌，那面超大的金色背景墙给人一种震撼的感觉。服务', '酒店很大气，一入户，大厅里金碧辉煌，那面超大的金色背景墙给人一种震撼的感觉。服务人员很热情，主动提行李，主动递水，主动发小礼物，电梯口的小姐姐每次一见面都要给小朋友一大把小点心，客服部也是有求必应。后面还有瀑布大花园，很漂亮。外面一出门就是地铁5号线，非常方便，离小蛮腰也很近。整体超赞。', '2024-02-15', 5, '[''整体满意度'', ''前台服务'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0231712000d7kkvnnBA2F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230l12000d7k88qq274D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '挺不错的，交通挺方便的', '挺不错的，交通挺方便的', '2024-07-30', 5, '[''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230512000exzm2r16556_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231y12000exzhytq0DB2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '此次广州之行第一站选择了花园酒店，非常满意。', '此次广州之行第一站选择了花园酒店，非常满意。
房间设施、服务态度都是应有的水平，建筑本身也是风景。
最打动我的还是它独特的气质，而且很明显地感觉到，管理方有意营造这种热气腾腾、繁花似锦、芬芳馥郁的梦幻感。
当然也有一些问题，譬如面盆里有霉渍，深夜外面修路的声音还很嘈杂。但氛围感到位让人可以忽略。', '2024-01-24', 5, '[''整体满意度'', ''房间设施'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235312000d135y7u3442_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236z12000d133fb69134_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230v12000d13it9kA493_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000d13e41gF495_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第二次入住了，价格有点贵但还是挺有当地特色的，服务不错。房间很大很舒服，虽然看得', '第二次入住了，价格有点贵但还是挺有当地特色的，服务不错。房间很大很舒服，虽然看得出已有一些些年代感了，但总体体验还是不错。每次checkin都会遇到阿联酋航空机组。唯一美中不足的是房间插座没有配备usb充电，最后问酒店借了一个充电器，也算是完美解决问题！', '2024-01-26', 4, '[''房间设施'', ''整体满意度'', ''价格合理性'']', '["[ \"https://dimg04.c-ctrip.com/images/0230p12000d1sphzo93CF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236x12000d1spi017B34_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231912000d1spkr7D643_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233n12000d1sq3020C05_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施有复古风，只是空调设备噪音太大', '设施有复古风，只是空调设备噪音太大', '2024-07-27', 4, '[''房间设施'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231i12000ex0t48o687B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234z12000ex0tg85853C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l12000ex0trw0DD48_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '亲子家庭出行，花园酒店的春节氛围浓郁，捏小泥人非常受孩子喜欢～', '亲子家庭出行，花园酒店的春节氛围浓郁，捏小泥人非常受孩子喜欢～
但是服务还是很受影响，没有欢迎水果，连住两晚，房间没有主动打扫。宝宝备品没有，床围没有，总之有点一言难尽', '2024-02-16', 3, '[''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231g12000d7qsqu72A0A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231k12000d7qvkdh7F63_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230812000d7qt41p91D6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234c12000d7qtol0E392_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间布局紧凑。进门在电梯后方，第一次遇到也是长见识了。', '房间布局紧凑。进门在电梯后方，第一次遇到也是长见识了。
洗澡水压大，很舒服。早餐在30楼，鸡蛋和面食自主选择下单，第一天吃不懂，原来配菜很多量很大，第二天就知道少点了，节约粮食。
大厅果真气派，真不愧是白金五星级酒店，香氛味道很不错，4楼的博物馆和后花园瀑布一定要去参观。
以后有机会再来。', '2024-01-30', 5, '[''房间设施'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235312000d2zovkr6AED_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236v12000d2zovkv75D2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236y12000d2zoxg46EE3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '阔别15年后再住花园酒店，没想到还这么棒。无论硬件设施还是服务质量绝对还是广州首', '阔别15年后再住花园酒店，没想到还这么棒。无论硬件设施还是服务质量绝对还是广州首选住宿酒店。酒店内后花园是国内众多高档酒店中难得一见的宝藏级花园。特别推荐三楼桃园馆的清蒸东星斑，非常好吃。', '2024-01-31', 5, '[''整体满意度'', ''公共设施'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231y12000d3a93yoDB2D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234e12000d3a9hwwD9EB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '在结婚28周年纪念日选择了入住花园酒店，跟着礼宾小哥参观了酒店25个打卡点，在酒', '在结婚28周年纪念日选择了入住花园酒店，跟着礼宾小哥参观了酒店25个打卡点，在酒店博物馆听了广州酒店历史文化发展的专属介绍。特意选择了在荔湾庭晚餐，听着故仔和粤语旧歌，聊起在江边吃过的艇子粥，胜利宾馆的虾饺，老广州喝茶时拿着单子围着干蒸烧卖车边拿一盅两件边盖印章的趣事，耳边响起黄家驹的“喜欢你”不由唱起来，感觉太好了。前台小姐姐给我们升级了粤韵房，穿着汉服和旗袍拍了好多照片。最后，没有浪漫情怀，不善表达的老公说了一句“还是很高兴的哦”为这个特别的纪念日画上了美好的句号。', '2023-11-26', 5, '[''前台服务'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235212000cmzglnuDB08_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230312000cmzgvd4E73A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232a12000cmzivuq1AE2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235l12000cmzk1zrC46B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231a12000cmzhmgb106B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231m12000cmzhre7AACC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000cmzlpbx9855_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236112000cmzhrqi433A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230r12000cmzkfa3B4EF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店不愧为老牌五星，卫生，服务都很不错，特别感谢前台niki服务意识和态度都', '花园酒店不愧为老牌五星，卫生，服务都很不错，特别感谢前台niki服务意识和态度都很好还帮忙升级了房间，下次还会选择这里', '2024-07-21', 5, '[''前台服务'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0235912000eup7iah53E9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232v12000eupbppt3539_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236c12000eupbaza8E73_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '怎么说呢，依然金碧辉煌的大堂，照旧熙熙攘攘的人流，办入住的时候说我订的房型只有5', '怎么说呢，依然金碧辉煌的大堂，照旧熙熙攘攘的人流，办入住的时候说我订的房型只有5层靠边的了，外面市政施工有噪音，给我们升级到套房，看了房间后发现原来是公寓楼不是客房，没有同意，出去吃饭回来后说安排好了还是原来的房型在20楼，能感觉到小伙子想尽力做到让客人满意，还好虽然晚上外面有施工但没影响休息。就是押金要第二天9点才能给退，感觉效率太低了，给人有点店大欺客的感觉。', '2024-01-30', 4, '[''前台服务'', ''退房/入住效率'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236f12000d2w2qpnB054_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235p12000d2w2jvs183F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236s12000d2w2p51E3C8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店的大招要从进入大门后开始——自接待厅起，一众充满岭南文化韵味的陈设与', '广州花园酒店的大招要从进入大门后开始——自接待厅起，一众充满岭南文化韵味的陈设与装饰，真的让人感觉走进了一座现代的艺术宫殿。接待厅的中央就陈列着当年那块“白金五星级酒店”的奖牌，它两侧的墙壁上分别挂着阳江手工漆画《百美图》与《百骏图》，静与动、柔与刚，相互呼应。进入大堂，最吸睛的莫过于前台背后的《红楼梦》大理石贴金壁画，它曾被国务院认证为全国最大的酒店大堂及镶金壁画。据说这副巨画由30多位工匠，花费7个多月才完工，用2公斤重的黄金做成20万片金箔，贴成了金陵十二钗的形象与故事...金庸先生2003年时也曾来此，并为这副画题字“花园酒店/如进荣国府/身在大观园”。与《红楼梦》壁画相对的墙上，是另一幅大理石壁画《广东水乡石刻壁画》，两幅壁画中间的空间，经常会更换放置一些限时的快闪展览装置，现在放置的是，主要面向孩子们的现场互动创作区，可以让他们在玻璃上随意进行色彩作画。', '2024-04-03', 5, '[''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230b12000dksynf916A6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233e12000dksyuibC2E5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231212000dksyhj37BC0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230412000dksyqdu86F8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232t12000dksyqjfAD05_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230z12000dksyxm7A624_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232d12000dksy859A0E9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000dksypuvA77C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233m12000dksyu6968FD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店富丽堂皇还有博物馆 卫生且干净', '酒店富丽堂皇还有博物馆 卫生且干净', '2024-08-12', 5, '[''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230n12000f3cfh4t2407_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230212000f3clfaa3C83_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230k12000f3c9vvq6901_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间布置很温馨，有种回家的感觉!床特别舒服，躺在上面特别放松!床垫非常柔软!下午', '房间布置很温馨，有种回家的感觉!床特别舒服，躺在上面特别放松!床垫非常柔软!下午茶小点心味道很甜蜜。棒!各种卫生用品也很干净!后花园也很漂亮!早餐特别丰盛!确实是米其林的大厨烹饪的。有机会还会光顾!', '2024-02-01', 5, '[''房间设施'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235o12000d3nno832A2E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232912000d3mueq2DD24_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235e12000d3npnikC121_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000d3nrjsj47D1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235i12000d3nh5bl5CDB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236f12000d3nw9apFE31_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '全家人都喜欢老牌五星，这次带老人和孩子在花园酒店住了五天，非常舒心。', '全家人都喜欢老牌五星，这次带老人和孩子在花园酒店住了五天，非常舒心。

三个大人一个孩子，订了两间房间。由于我是金卡会员，升级到了64平粤韵房，老人的房间也一起升级到了粤韵房。

粤韵房设施良好保养得宜，补给充足干净卫生。

员工礼貌得体，处处体现五星大酒店风范。

还有真的好漂亮啊！！！大堂阔气，瀑布霸气，不敢想象38年前就有这么好的酒店了。

来之前有人跟我说花园酒店很旧了很老了不要住，我想说完全不旧，保养相当好，前台小姐姐也说旧的房间也一直在做升级改造，以后估计都会以全新面貌示人。

位置相当好！旁边利苑、点都德、八合里，吃东西太方便啦，叫外卖也好方便，吃的可太多了！！！

下面说下不太满意的。

办理入住好慢啊……刚开始一个外籍员工接待我，怎么说都不给我升级到粤韵，说只能升级到同面积新装修的房间，最后中国员工过来跟他说是可以的，外籍员工一脸懵说自己不知道。??

行政餐厅一般般哈，吃的东西好少，而且还搞过几次乌龙，一会儿说没查到行政待遇，一会儿又说有了，感觉外籍员工还是不太行。孩子起得晚，想说不在行政餐厅吃，让大人一起打包回去吃也不让，又不是吃完了再打包，不理解为什么不可以。

泳池只有露天的??。

瑕不掩瑜，总体入住还是很满意的，本来只订了3天，由于很满意又续住了两天，以后肯定也还会去住??。

对了，他们泳池后面有个儿童乐园，但是没啥人知道，没有孩子玩儿??。', '2024-01-07', 4, '[''整体满意度'', ''房间设施'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0235u12000cvn7nqzDC7E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233012000cvnhrquE0D8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233t12000cvnhc4jB2CA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236t12000cvnjolt6ABF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235u12000cvno5cpC76C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235112000cvnods79B22_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236212000cvndglz1FA7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235612000cvnn52qB395_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236z12000cvnoosz5096_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店的工作人员服务很好，套房重新装修环境不错', '花园酒店的工作人员服务很好，套房重新装修环境不错', '2024-05-26', 5, '[''前台服务'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233w12000e6ciepuADD3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232j12000e6ccokpDE90_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233o12000e6cxnxy1540_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境真的是一流，中餐厅桃园馆菜品质量很高，服务员热情友好。客房卫生做的很好，房间', '环境真的是一流，中餐厅桃园馆菜品质量很高，服务员热情友好。客房卫生做的很好，房间设施齐全布局合理，不足之处是没有浴缸，酒店后花园非常值得看看走走，酒店的四楼博物馆也很值得一看，酒店服务人员态度都不错，就是前台接待人员态度一般，工作能力有些欠缺，退房后忘记退押金，居然开票资料还丢失了，经电话联系酒店后及时退还了押金并开具了发票，这点有些不可思议，入住多家广州五星级酒店还是第一次碰到。', '2023-11-26', 4, '[''前台服务'', ''房间设施'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230i12000cn0xiy814C5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232112000cn1169j2281_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236f12000cn0vq0xEC3A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235e12000cn0zrbs4E9B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232x12000cn11akm976A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233912000cn0yaz59AB2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232212000cn11cp63C9D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235k12000cn11cul3A7A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231312000cn11a5sAE59_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第二次入住花园饭店，大堂的“金陵十二钗”大气磅礴，很有年代感的酒店，但是保养的很', '第二次入住花园饭店，大堂的“金陵十二钗”大气磅礴，很有年代感的酒店，但是保养的很好，房间舒适，床垫有点偏软，酒店的网红花园和瀑布很好逛，拍照也出片。我们还打卡了酒店的博物馆，下次来广州，应该还会选择花园！', '2024-02-12', 5, '[''整体满意度'', ''公共设施'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230t12000d6mqj4k6A1D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235s12000d6mq6i86CA9_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '算是地标性的酒店了，就在淘金路地铁站旁边，附近知名的饭店酒楼很多，打车也很方便。', '算是地标性的酒店了，就在淘金路地铁站旁边，附近知名的饭店酒楼很多，打车也很方便。但设施太老了，基础房型对老人洗浴不太友好，容易滑倒。建议带老人家的，升级房型。', '2024-03-04', 3, '[''交通便利性'', ''周边配套'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230s12000dc8uugv605B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q12000dc8r59eEF0E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235712000dc8fkxj7BE4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间太老旧，给的房间门缝漏光，不隔音。一张床的床垫还有一个坑。但是都说老牌花园酒', '房间太老旧，给的房间门缝漏光，不隔音。一张床的床垫还有一个坑。但是都说老牌花园酒店是粤式生活的代表还是住来这里。环境没得说，尤其是花园太美。早餐非常棒。希望抓紧改造老旧破的房间，别再让我们下次运气不好碰上这么差的房间。', '2024-02-19', 3, '[''房间设施'', ''安静程度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235912000d8pwea7260E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232e12000d8pws632CA9_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '入住愉快，但是一定要搭配套餐入住对连住不是很友好。', '入住愉快，但是一定要搭配套餐入住对连住不是很友好。', '2024-05-24', 4, '[''性价比'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230y12000e4v1q1mF350_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233b12000e4tued96B74_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233o12000e4u7lh361E7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店位置很好，晚上吃了晚饭可以步行去花城广场，走过可以看到小蛮腰，酒店的22楼办', '酒店位置很好，晚上吃了晚饭可以步行去花城广场，走过可以看到小蛮腰，酒店的22楼办入住，也可以看到小蛮腰，周边吃饭很方便，离陶陶居很近，离春，夏，秋，冬商场很近，早餐品钟很丰富，广州的特色早餐都有，还有豆浆，豆浆是现磨的，味道很浓，上面还有一层豆皮，下次来广州还会入住这家酒店', '2024-01-18', 4, '[''周边配套'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231u12000cywttyq21A3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232112000cywti12A3F1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232112000cywtquaD608_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间舒适，干净卫生，住的很舒心。过年酒店很有节日气氛，服务态度很好，帮忙拍照，拿', '房间舒适，干净卫生，住的很舒心。过年酒店很有节日气氛，服务态度很好，帮忙拍照，拿行李，贴心用心暖心。
交通便利，出行方便。
酒店很有历史底蕴，博物馆，木质旋转楼梯，红楼梦壁画，后花园都值得一逛。', '2024-02-15', 5, '[''整体满意度'', ''前台服务'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0233u12000d7oo7zlB226_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000d7oknnp43DA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232w12000d7oo7l0A9AB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231u12000d7oro2l9727_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234812000d7ojkot0449_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231p12000d7ostmkCB72_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '逢人就推荐，花园酒店的大堂太美了，一个有40年底蕴的酒店的装修媲美新酒店。感谢前', '逢人就推荐，花园酒店的大堂太美了，一个有40年底蕴的酒店的装修媲美新酒店。感谢前台小姐姐给我升级了粤韵，秒变套房非常惊喜，哈哈。酒店内有博物馆和小花园，还有n多个餐厅，在等房间时，酒店内吃饭，再去参观博物馆溜达小花园，完美。', '2024-01-21', 5, '[''整体满意度'', ''公共设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234o12000czrcqvt8AA7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232a12000czr0jcxE977_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232x12000czrh9ni8A5D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231j12000czr8u7vD8EB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236b12000czrcae0F485_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f12000czrm42u2640_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店很有历史，但设施并不陈旧，尤其公共区域维护非常好。房间内设施不奢华但是好用', '酒店很有历史，但设施并不陈旧，尤其公共区域维护非常好。房间内设施不奢华但是好用

酒店服务人员素质非常高，热情真诚得体。酒店内餐厅也是素质相当高

非常满意的入住体验', '2024-02-14', 5, '[''整体满意度'', ''公共设施'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233012000d7ahm8iB0FF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '整体感觉都非常好，特别感谢前台漂亮的小姐姐给我父母升了房间，让他们感受了不一样的', '整体感觉都非常好，特别感谢前台漂亮的小姐姐给我父母升了房间，让他们感受了不一样的酒店感受。房间很大很舒服，酒店每个人的服务都是100分，早餐也很丰盛，是个完美的度假体验。', '2024-02-08', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234l12000d5rq4z54A63_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233r12000d5rpz8m71C8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236m12000d5rp89sAE47_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '每次小假期都会选择本地出游，首选都是花园酒店，特别喜欢这里的游泳池，大堂的布置很', '每次小假期都会选择本地出游，首选都是花园酒店，特别喜欢这里的游泳池，大堂的布置很有特色每次都眼前一亮，最重要的是五星级的服务和卫生真的让人放心。特别感谢迎送岗的小爱，中秋节当天很开心收到酒店月饼～???', '2024-09-21', 5, '[''公共设施'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0233a12000fobgkwrD74D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230e12000fob3cq52989_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232i12000foblep23348_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店属于店如其名，花园真的很大很有逛小公园的感觉，邓爷爷题的字～很好逛，酒店', '花园酒店属于店如其名，花园真的很大很有逛小公园的感觉，邓爷爷题的字～很好逛，酒店内的饭店也是米其林推荐，的确味道都很不错，就是真的很贵～500一顿完全不够～毕竟广州物廉价美的食物真的很多～不过味道的确很不错，都很好吃～就是旅游还要回来吃饭其实不大方便哈哈哈??，适合local或者行程很朵悠悠的朋友～性价比还是很不错滴
设施：好像给我升级了新装修的套房定的我看有地毯，升级的这个说是新的，是没地毯的，但说实话房间有点旧，我这间墙面和沙发，还有点脏，就大堂和花园是加分项，房间就要扣分了，不过能看到半个小蛮腰还挺大的，就扣一分意思意思吧
卫生：房间卫生一般，可能因为墙面和椅子真的显得很脏
环境：很不错，本身地理位置很好门口就是地铁站，去地标距离都不远，地铁又实惠，又方便，打车看路况地段感觉都满堵的，来回地铁乘三天20大概??
服务：外国客人挺多的，所以服务员也是各个肤色，都很不错～客气??

最后一天看到了谭咏麟哈哈哈哈～
对了每天还有小点心', '2024-01-25', 4, '[''周边配套'', ''性价比'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0232812000d1eynhwB5E6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233i12000d1f56ibB5BF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232712000d1f23b92B36_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '入住体验大大超过预期，真不愧为是中国酒店业的标杆，很有老钱风，设施非常齐全和豪华', '入住体验大大超过预期，真不愧为是中国酒店业的标杆，很有老钱风，设施非常齐全和豪华。居然还有博物馆，几个餐厅都是顶级的。服务员很热情专业训练有素，特别感谢服务员小玲。', '2024-08-31', 5, '[''整体满意度'', ''公共设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236g12000fbwh5858EF9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231h12000fbwc2wf3B60_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '对酒店的服务人员的态度非常满意，见面问好有礼貌，帮助按电梯，房间卫生干净整洁，有', '对酒店的服务人员的态度非常满意，见面问好有礼貌，帮助按电梯，房间卫生干净整洁，有胶囊咖啡机，有欢迎水果和鲜花，酒店还有后花园，小桥流水锦鲤满池，地理位置优越，对面就是广州友谊商店，地铁淘金站就在酒店正门，这两天广州气温骤降酒店马上给热空调，我们是下午的飞机经理还帮我们延迟退房到14:00，很温馨的酒店，下次来广州再入住这家！', '2024-01-24', 5, '[''前台服务'', ''卫生状况'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0230812000d0zhdlwEF74_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233w12000d0zgs51A32E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000d0zgvtl23EC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236g12000d0zhpueD5DC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务很好，房间很舒服，一千多的房间里面的胶囊咖啡机有三种口味，可供选择，大堂也很', '服务很好，房间很舒服，一千多的房间里面的胶囊咖啡机有三种口味，可供选择，大堂也很舒服明亮，总体来说感觉很好，一共住了四个晚上，出门非常方便，好吃的有名气的餐厅都在附近一公里范围。', '2024-01-27', 5, '[''整体满意度'', ''房间设施'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0230k12000d23wl4m2680_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234m12000d23qbpb56C6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '走进大堂就是一个繁花迷人眼，让人目不暇接。卫生据肉眼可见还是很干净的，客房服务员', '走进大堂就是一个繁花迷人眼，让人目不暇接。卫生据肉眼可见还是很干净的，客房服务员，门童等都很热情，前台Gillian服务非常热情，亲切，周到，有求必应！', '2024-02-07', 5, '[''前台服务'', ''客房服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230v12000d5gapxiACED_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000d5gbu84A715_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230u12000d5gcb4pFC31_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232g12000d5gax6a83F4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236s12000d5gc95r882E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231112000d5gbhbu6469_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233t12000d5gcmn9B24C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236e12000d5gcihs77BE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235112000d5gbev736C3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧是白金五星，酒店地理位置优越，闹中取静，自带岭南风格的花园，还贴心地送了小点', '不愧是白金五星，酒店地理位置优越，闹中取静，自带岭南风格的花园，还贴心地送了小点心', '2024-04-12', 5, '[''整体满意度'', ''周边配套'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231z224x8uhjlnud9651_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232o224x8uhkjgps8E8D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231i224x8uhk42ewF4F6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q224x8uhk98g888F9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r224x8uhka9nl1130_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '大堂就很有春节气氛！房间应该经历过翻新，设施和装潢布局都很不错。被子估计是绒，轻', '大堂就很有春节气氛！房间应该经历过翻新，设施和装潢布局都很不错。被子估计是绒，轻薄又保暖。洗漱用具的盒子设计也充满巧思，可以构成一幅完整的广州市花木棉图案。', '2024-02-09', 5, '[''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231t12000d62b7p18A20_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233612000d628op81F3D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236x12000d62c4jc3420_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店非常不错，是全国三个白金五星级酒店之一，入住时正好遇到中越一个商会搞活动，虽', '酒店非常不错，是全国三个白金五星级酒店之一，入住时正好遇到中越一个商会搞活动，虽晚了一些但酒店给升级了套房而且还给了下午茶。酒店服务非常专业，感谢Rebecca小钟的热心服务和讲解，酒店近6号地铁交通便利，而且酒店有大巴直接到澳门几个固定地点，不过每天只有8:35这一班。酒店的瀑布餐厅很有特色，老人孩子非常满意，非常不错的一次体验。下次来广东还会再次入住。', '2025-01-17', 5, '[''整体满意度'', ''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234i12000humufzq465E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235612000humobj20E65_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234q12000humgr1355E9_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务很好，身体不舒服李文（名字写的不知道对不对）小姐姐帮忙处理加急拿房，房间吐了', '服务很好，身体不舒服李文（名字写的不知道对不对）小姐姐帮忙处理加急拿房，房间吐了清洁的工作人员特别及时有耐心的清理。定的房型12岁以下免费加了床，非常适合我们这种娃年龄小块头大的。周边有陶陶居，点都德，广州酒家，常来小聚，步行可到，非常方便。', '2025-02-06', 5, '[''前台服务'', ''客房服务'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0233o12000ic88y3n12FC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233o12000ic88fkv7455_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231e12000ic7qeurA1AE_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '和同事相约游广东，恰逢圣诞在广州花园酒店连住2晚实在是选对了。', '和同事相约游广东，恰逢圣诞在广州花园酒店连住2晚实在是选对了。
这个酒店太让人惊艳了，他们是全国首批三家白金五星级饭店之一，而且是华南地区唯一获选的中国自主品牌酒店。
贝聿铭为花园酒店勾画了建设蓝图，***为花园酒店奠基基石，邓小平为花园酒店亲笔题写了店名！
西点做得非常正宗美味，酒店米其林提名的餐厅不止一个，瀑布餐厅很有特色，服务非常好，非常满意，必须五星好评??', '2024-01-22', 5, '[''餐饮设施'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230v12000d0a91nt05F9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232f12000d0acyi6CB42_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233j12000d0aodxk3210_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235p12000d0ao6vsE3E8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233w12000d0aodjg03F9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236712000d0aodxq9FF4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235o12000d0aodjk6D62_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000d0ao6w23884_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236z12000d0ap7yq145B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '就在地铁淘金站出口，附近也很热闹，服务非常好，工作人员到处都是，房间装修也不错，', '就在地铁淘金站出口，附近也很热闹，服务非常好，工作人员到处都是，房间装修也不错，除了卫生间没隔断有点不方便。新年有舞狮，有小摊，晚上还有驻场表演。', '2024-02-17', 5, '[''交通便利性'', ''周边配套'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232l12000d89zioq5C04_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234712000d8a0q2e4144_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常满意的一次住宿体验，颇具性价比。酒店很漂亮，交通方便，门口就是公交站和地铁站', '非常满意的一次住宿体验，颇具性价比。酒店很漂亮，交通方便，门口就是公交站和地铁站，服务人员态度很好，见面总是微笑打招呼，房间卫生还不错，没有异味。就是附近夜里有施工，稍微有点吵。花园很漂亮，常有打卡拍照的，二楼的早茶味道很不错。酒店旁边点都德，广州酒家离得很近。', '2024-01-09', 5, '[''交通便利性'', ''性价比'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230x12000cw9q2dxC412_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235m12000cwa3qxfE9F8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '地理位置：酒店位于淘金地铁站出口处，前面还有数条公交线路，出行极其便利。', '地理位置：酒店位于淘金地铁站出口处，前面还有数条公交线路，出行极其便利。
环境：酒店大堂金碧辉煌，前台的红楼梦壁画真是点睛之笔。
服务：从入口处的服务人员，到前台办理入住的接待人员，还有客房、餐厅的工作人员全程热情接待，笑脸相迎，让人如沐春风，可见酒店的管理水准到位，不愧为白金酒店的称谓??
餐饮：酒店的早餐品种繁多，菜品新鲜可口，服务人员热情友好，值得称赞??', '2024-01-25', 5, '[''交通便利性'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230g12000d1g97mmEF38_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236k12000d1g8ift3712_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230s12000d1gif7lD1F2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第二次住的花园酒店', '第二次住的花园酒店
传统地道的酒店年味是特别足，处处充满着粵广文化，另有一番滋味，早餐后逛逛花园，鸟语花香.

细致的服务也凸显出酒店管理的用心。', '2024-02-16', 5, '[''整体满意度'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233c12000d80le8i1204_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230r12000d813rbg9CC2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232x12000d812vuf8D1A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '网约车司机是个健谈的广州人，听了他对酒店的推荐，临时决定在广州多停留一晚，结果出', '网约车司机是个健谈的广州人，听了他对酒店的推荐，临时决定在广州多停留一晚，结果出乎意料地满意。酒店如其名，真得像个花园一样，会推荐给朋友们。升级的粤韵套房宽敞，设施很新。参观了位于4层的酒店博物馆，才知道酒店始建于1984年，还是邓小平先生题字。酒店内及周边餐厅很多，丰俭由人。交通便捷，离地铁就2-3分钟步行距离。唯一的建议是夜间关闭瀑布，减少噪声。', '2024-01-09', 5, '[''整体满意度'', ''交通便利性'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236s12000cw6u2rmDCCC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230712000cw6mqza879F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234012000cw6ibq66A9D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235g12000cw6s4olDDC4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236e12000cw6rjefB8E4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232k12000cw6s069D9E1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232e12000cw6vn9b8480_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235412000cw6vmom7B92_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常好的酒店，下次还会再入住！酒店的餐厅要去试试！', '非常好的酒店，下次还会再入住！酒店的餐厅要去试试！', '2024-05-18', 5, '[''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230t12000e22mqyr41DD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236912000e22n370E9E5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236k12000e22ll11EC72_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02